1206:     /**
1207:      * Add a service. If a service of the same type with the same algorithm
1208:      * name exists, and it was added using {@link #putService putService()},
1209:      * it is replaced by the new service.
1210:      * This method also places information about this service
1211:      * in the provider's Hashtable values in the format described in the
1212:      * {@extLink security_guide_jca
1213:      * Java Cryptography Architecture (JCA) Reference Guide}.
1214:      *
1215:      * @param s the Service to add
1216:      *
1217:      * @throws NullPointerException if s is {@code null}
1218:      *
1219:      * @since 1.5
1220:      */
1221:     protected void putService(Service s) {
1222:         checkInitialized();
1223:         if (debug != null) {
1224:             debug.println(name + ".putService(): " + s);
1225:         }
1226:         if (s == null) {
1227:             throw new NullPointerException();
1228:         }
1229:         if (s.getProvider() != this) {
1230:             throw new IllegalArgumentException
1231:                     ("service.getProvider() must match this Provider object");
1232:         }
1233:         String type = s.getType();
1234:         String algorithm = s.getAlgorithm();
1235:         ServiceKey key = new ServiceKey(type, algorithm, true);
1236:         implRemoveService(serviceMap.get(key));
1237:         serviceMap.put(key, s);
1238:         for (String alias : s.getAliases()) {
1239:             serviceMap.put(new ServiceKey(type, alias, true), s);
1240:         }
1241:         servicesChanged = true;
1242:         synchronized (this) {
1243:             putPropertyStrings(s);
1244:             checkAndUpdateSecureRandom(type, algorithm, true);
1245:         }
1246:     }
