1248:     private void checkAndUpdateSecureRandom(String type, String algo,
1249:             boolean doAdd) {
1250:         if (type.equalsIgnoreCase("SecureRandom")) {
1251:             if (doAdd) {
1252:                 prngAlgos.add(algo);
1253:             } else {
1254:                 prngAlgos.remove(algo);
1255:             }
1256:             if (debug != null) {
1257:                 debug.println((doAdd? "Add":"Remove") +
1258:                         " SecureRandom algo " + algo);
1259:             }
1260:         }
1261:     }
