1263:     // used by new SecureRandom() to find out the default SecureRandom
1264:     // service for this provider
1265:     Service getDefaultSecureRandomService() {
1266:         checkInitialized();
1267: 
1268:         if (!prngAlgos.isEmpty()) {
1269:             String algo = prngAlgos.iterator().next();
1270:             // IMPORTANT: use the Service obj returned by getService(...) call
1271:             // as providers may override putService(...)/getService(...) and
1272:             // return their own Service objects
1273:             return getService("SecureRandom", algo);
1274:         }
1275: 
1276:         return null;
1277:     }
