1281:      * Hashtable.
1282:      */
1283:     private void putPropertyStrings(Service s) {
1284:         String type = s.getType();
1285:         String algorithm = s.getAlgorithm();
1286:         // use super() to avoid other processing
1287:         super.put(type + "." + algorithm, s.getClassName());
1288:         for (String alias : s.getAliases()) {
1289:             super.put(ALIAS_PREFIX + type + "." + alias, algorithm);
1290:         }
1291:         for (Map.Entry<UString,String> entry : s.attributes.entrySet()) {
1292:             String key = type + "." + algorithm + " " + entry.getKey();
1293:             super.put(key, entry.getValue());
1294:         }
1295:     }
