1303:         String algorithm = s.getAlgorithm();
1304:         // use super() to avoid other processing
1305:         super.remove(type + "." + algorithm);
1306:         for (String alias : s.getAliases()) {
1307:             super.remove(ALIAS_PREFIX + type + "." + alias);
1308:         }
1309:         for (Map.Entry<UString,String> entry : s.attributes.entrySet()) {
