1315:     /**
1316:      * Remove a service previously added using
1317:      * {@link #putService putService()}. The specified service is removed from
1318:      * this {@code Provider}. It will no longer be returned by
1319:      * {@link #getService getService()} and its information will be removed
1320:      * from this provider's Hashtable.
1321:      *
1322:      * @param s the Service to be removed
1323:      *
1324:      * @throws NullPointerException if s is {@code null}
1325:      *
1326:      * @since 1.5
1327:      */
1328:     protected void removeService(Service s) {
1329:         checkInitialized();
1330:         if (debug != null) {
1331:             debug.println(name + ".removeService(): " + s);
1332:         }
1333:         if (s == null) {
1334:             throw new NullPointerException();
1335:         }
1336:         implRemoveService(s);
1337:     }
1338: 
1339:     private void implRemoveService(Service s) {
1340:         if ((s == null) || serviceMap.isEmpty()) {
1341:             return;
1342:         }
1343:         String type = s.getType();
1344:         String algorithm = s.getAlgorithm();
1345:         ServiceKey key = new ServiceKey(type, algorithm, false);
1346:         Service oldService = serviceMap.get(key);
1347:         if (s != oldService) {
1348:             return;
1349:         }
1350:         servicesChanged = true;
1351:         serviceMap.remove(key);
1352:         for (String alias : s.getAliases()) {
1353:             serviceMap.remove(new ServiceKey(type, alias, false));
1354:         }
1355: 
1356:         removePropertyStrings(s);
1357:         checkAndUpdateSecureRandom(type, algorithm, false);
1358:     }
