199: 
200:         /*
201:          * Algorithm Parameter engine
202:          */
203:         // "AlgorithmParameters.EC SupportedCurves" prop used by unit test
204:         boolean firstCurve = true;
205:         StringBuilder names = new StringBuilder();
206: 
207:         for (NamedCurve namedCurve : List.of(
208:                 CurveDB.P_256, CurveDB.P_384, CurveDB.P_521)) {
209:             if (!firstCurve) {
210:                 names.append("|");
211:             } else {
212:                 firstCurve = false;
213:             }
214: 
215:             names.append("[");
216:             String[] commonNames = namedCurve.getNameAndAliases();
217:             for (String commonName : commonNames) {
218:                 names.append(commonName);
219:                 names.append(",");
220:             }
221: 
222:             names.append(namedCurve.getObjectId());
223:             names.append("]");
224:         }
225: 
226:         HashMap<String, String> apAttrs = new HashMap<>(ATTRS);
227:         apAttrs.put("SupportedCurves", names.toString());
228: 
229:         putService(new ProviderServiceA(this, "AlgorithmParameters",
230:             "EC", "sun.security.util.ECParameters", apAttrs));
